    steps: [
      { id: "tomato-cook", n: 1, text: t("Simmer tomatoes, cashews, ginger-garlic and 1 cup water for 15 minutes, then cool slightly.", "टमाटर, काजू, अदरक-लहसुन और 1 कप पानी 15 मिनट उबालें, फिर हल्का ठंडा करें।", "Tamatar, kaju, adrak-lehsun aur 1 cup paani 15 minute ubalo, phir halka thanda karo."), spoken: t("Everything for the gravy goes into one pot — tomatoes, cashews, ginger, garlic, water. Fifteen minutes of simmering, no stirring worries.", "ग्रेवी का सब कुछ एक पतीले में — टमाटर, काजू, अदरक, लहसुन, पानी। पंद्रह मिनट उबालें, चलाने की चिंता नहीं।", "Gravy ka sab kuch ek pateele mein — tamatar, kaju, adrak, lehsun, paani. Pandrah minute ubalo, chalane ki chinta nahi."), cue: t("Tomato skins split and cashews look swollen.", "टमाटर के छिलके फटें और काजू फूले दिखें।", "Tamatar ke chhilke fatein aur kaju phoole dikhein."), photo: "stage-tomato-simmer", durationSec: 900, attention: "passive", risk: "normal", checkInIntervalSec: 180, flame: 3, stage: "simmer", recovery: [{ id: "dry-pot", failure: t("Water is drying up", "पानी सूख रहा है", "Paani sookh raha hai"), fix: t("Add half a cup of hot water and lower the flame.", "आधा कप गरम पानी डालें और आँच कम करें।", "Aadha cup garam paani daalo aur flame kam karo.") }] },
      { id: "blend", n: 2, text: t("Blend smooth and strain back into the kadhai for a silky gravy.", "पीसकर छानें और रेशमी ग्रेवी के लिए वापस कड़ाही में डालें।", "Pees kar chhaano aur silky gravy ke liye wapas kadhai mein daalo."), spoken: t("Blend it velvet-smooth, then strain. The strainer is the difference between homemade and restaurant texture — don't skip it.", "मखमली पीसें, फिर छानें। छलनी ही घर और रेस्तराँ के फ़र्क़ को मिटाती है — छोड़ें नहीं।", "Velvet-smooth peeso, phir chhaano. Chhalni hi ghar aur restaurant ke fark ko mitati hai — skip mat karo."), cue: t("Glossy orange-red purée with no seeds or skin.", "चमकदार नारंगी-लाल प्यूरी, न बीज न छिलका।", "Glossy orange-red puree, na beej na chhilka."), photo: "stage-tomato-puree", attention: "active", risk: "normal", flame: 1, stage: "prep", recovery: [{ id: "no-strainer", failure: t("No strainer at home", "छलनी नहीं है", "Chhalni nahi hai"), fix: t("Blend one extra minute; the gravy will be slightly rustic but delicious.", "एक मिनट और पीसें; ग्रेवी थोड़ी देसी पर स्वादिष्ट रहेगी।", "Ek minute aur peeso; gravy thodi desi par tasty rahegi.") }] },
      { id: "makhani", n: 3, text: t("Melt butter, bloom Kashmiri mirch 5 seconds, pour in the purée. Simmer 10 minutes.", "मक्खन पिघलाएँ, कश्मीरी मिर्च 5 सेकंड खिलाएँ, प्यूरी डालें। 10 मिनट पकाएँ।", "Makkhan pighlao, Kashmiri mirch 5 second khilao, puree daalo. 10 minute pakao."), spoken: t("Butter melts, mirch blooms five seconds for colour, then the purée. Careful, it splutters. Ten gentle minutes now.", "मक्खन पिघले, मिर्च पाँच सेकंड रंग के लिए, फिर प्यूरी। सावधान — छींटे उड़ेंगे। अब दस मिनट हल्की आँच।", "Makkhan pighle, mirch paanch second rang ke liye, phir puree. Dhyaan — chheente udenge. Ab das minute halki aanch."), cue: t("Gravy darkens a shade and butter dots the surface.", "ग्रेवी एक शेड गहरी हो, ऊपर मक्खन के दाने दिखें।", "Gravy ek shade dark ho, upar makkhan ke daane dikhein."), photo: "stage-butter-melt", durationSec: 600, attention: "passive", risk: "high", checkInIntervalSec: 120, flame: 2, stage: "simmer", recovery: [{ id: "splutter", failure: t("It's spluttering everywhere", "हर तरफ़ छींटे उड़ रहे हैं", "Har taraf chheente ud rahe hain"), fix: t("Partly cover with a lid, leaving a steam gap. Lower the flame.", "ढक्कन आधा ढकें, भाप की जगह छोड़ें। आँच कम करें।", "Lid aadha dhako, steam ki jagah chhodo. Flame kam karo.") }] },
      { id: "finish", n: 4, text: t("Add paneer, cream, salt, pinch of sugar. Two minutes, then kasuri methi and the last butter.", "पनीर, क्रीम, नमक, चुटकी चीनी। दो मिनट, फिर कसूरी मेथी और बचा मक्खन।", "Paneer, cream, namak, pinch cheeni. Do minute, phir kasuri methi aur bacha makkhan."), spoken: t("Paneer and cream go in for just two minutes. Off the flame, crush kasuri methi over and swirl the last butter through. Done.", "पनीर और क्रीम सिर्फ़ दो मिनट। आँच बंद कर, ऊपर कसूरी मेथी मसलें और बचा मक्खन घुमा दें। तैयार।", "Paneer aur cream sirf do minute. Flame off karke, upar kasuri methi maslo aur bacha makkhan ghuma do. Ready."), cue: t("Silky orange gravy, soft cubes, methi aroma rising.", "रेशमी नारंगी ग्रेवी, नरम पनीर, मेथी की खुशबू।", "Silky orange gravy, naram paneer, methi ki khushbu."), photo: "paneer-butter-masala", durationSec: 120, attention: "active", risk: "normal", flame: 1, stage: "finish", recovery: [{ id: "too-tangy", failure: t("Too tangy", "बहुत खट्टा", "Bahut khatta"), fix: t("Another small pinch of sugar and a spoon of cream will round it off.", "एक और चुटकी चीनी और चम्मच क्रीम से संतुलन आ जाएगा।", "Ek aur pinch cheeni aur spoon cream se balance aa jayega.") }] }
    ]
